function nearestKmForCategory(
  cat: string,
  startCoords: { lat: number; lng: number },
  ctx: CategoryCoverageContext
): number | null {
  const distances: number[] = [];
  const { catalogDocs, primaryLocale, guestLocale, gems, features, discoveredPlaces, trails } =
    ctx;

