    if (!key) continue;
    const primary = index.get(key) || (raw || '').trim();
    const dedupeKey = primary.toLowerCase();
    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);
    out.push(primary);
  }
  return out;
}

