  latitude: string | number,
  longitude: string | number,
  label?: string
): string {
  const coords = `${latitude},${longitude}`;
  const query = label?.trim() ? `${label} ${coords}` : coords;
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(query)}`;
}

