export function bookingWhatsAppPhone(booking: {
  guestWhatsapp?: string;
  guestPhone?: string;
}): string | null {
  const raw = (booking.guestWhatsapp || booking.guestPhone || '').trim();
  if (!raw || raw === '—') return null;
  return buildWhatsAppChatUrl(raw) ? raw : null;
}

