export function getCategoryKnowledgeMode(knowledge: string): CategoryKnowledgeMode {
  const text = knowledge.trim();
  if (/\[AREAS\s+ONLY\]/i.test(text)) return 'areas';
  if (/\[BUSINESS\s+ONLY\]/i.test(text)) return 'business';
