/**
 * Fairness layer for database picks shown to guests.
 *
 * Goal: spread exposure across all of a host's gems / features instead of
 * always surfacing the same closest items. Items shown recently are pushed
 * down behind fresh ones inside the same distance band.
 */

const STORAGE_KEY = 'vailo:recentPicks:v1';
const MAX_ENTRIES = 80;
const FRESHNESS_WINDOW_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

type Entry = { key: string; ts: number };

/** Item shape used for key computation — only the identifying fields. */
type Identifiable = {
  name?: string;
  title?: string;
  googlePlaceId?: string;
  googleMapsUrl?: string;
  latitude?: number;
  longitude?: number;
  lat?: number;
  lng?: number;
};

function safeRead(): Entry[] {
  if (typeof window === 'undefined') return [];
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    const now = Date.now();
    return parsed.filter(
      (entry: unknown): entry is Entry =>
        !!entry &&
        typeof entry === 'object' &&
        typeof (entry as Entry).key === 'string' &&
        typeof (entry as Entry).ts === 'number' &&
        now - (entry as Entry).ts < FRESHNESS_WINDOW_MS
    );
  } catch {
    return [];
  }
}

function safeWrite(entries: Entry[]): void {
  if (typeof window === 'undefined') return;
  try {
    const trimmed = entries
      .slice()
      .sort((a, b) => b.ts - a.ts)
      .slice(0, MAX_ENTRIES);
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(trimmed));
  } catch {
    // Ignore quota / private-mode errors — fairness is best-effort.
  }
}

function bareGooglePlaceId(raw: string | undefined): string | null {
  if (!raw) return null;
  const cleaned = String(raw).replace(/^places\//, '').trim();
  return cleaned || null;
}

/** Stable identifier for an item — same key across runs identifies the same place. */
export function pickKeyForItem(item: Identifiable | null | undefined): string | null {
  if (!item) return null;

  const placeId = bareGooglePlaceId(item.googlePlaceId);
  if (placeId) return `id:${placeId}`;

  if (typeof item.googleMapsUrl === 'string') {
    const match = item.googleMapsUrl.match(/[?&](?:query_place_id|destination_place_id)=([^&]+)/i);
    if (match) return `id:${decodeURIComponent(match[1])}`;
  }

  const lat = item.latitude ?? item.lat;
  const lng = item.longitude ?? item.lng;
  if (typeof lat === 'number' && typeof lng === 'number' && !isNaN(lat) && !isNaN(lng)) {
    return `geo:${lat.toFixed(3)},${lng.toFixed(3)}`;
  }

  const name = (item.name ?? item.title ?? '').toString().toLowerCase().trim();
  const compact = name.replace(/[^a-z0-9\u0370-\u03ff]/g, '');
  if (compact) return `name:${compact}`;

  return null;
}

/** Set of item keys shown in the last freshness window. */
export function getRecentlyShownKeys(): Set<string> {
  return new Set(safeRead().map((entry) => entry.key));
}

/** Record that these item keys were just shown to the guest. */
export function markItemsShown(items: Array<Identifiable | null | undefined>): void {
  const keys = items
    .map((item) => pickKeyForItem(item))
    .filter((k): k is string => !!k);
  if (!keys.length) return;

  const existing = safeRead();
  const now = Date.now();
  const map = new Map<string, number>(existing.map((entry) => [entry.key, entry.ts]));
  for (const key of keys) {
    map.set(key, now); // overwrite with newest timestamp
  }
  safeWrite(Array.from(map.entries()).map(([key, ts]) => ({ key, ts })));
}

/** Manual clear (for debugging / "forget me" actions). */
export function resetPicksFairness(): void {
  if (typeof window === 'undefined') return;
  try {
    window.localStorage.removeItem(STORAGE_KEY);
  } catch {
    // ignore
  }
}

/**
 * Guest "thumbs up / thumbs down" feedback per recommendation.
 *
 * Stored at:  properties/{propertyId}/picksFeedback/{docId}
 * where docId is a deterministic hash of the item key (Place ID / coords / name)
 * so duplicate places get aggregated.
 *
 * The doc carries running counts + the latest local vote so the same guest can
 * toggle without inflating the totals. We never store who voted.
 */

import {
  doc,
  getDoc,
  serverTimestamp,
  setDoc,
  updateDoc,
  increment,
} from 'firebase/firestore';
import { db } from './firebase';
import { pickKeyForItem } from './picksFairness';

export type FeedbackVote = 'up' | 'down' | null;

const LOCAL_VOTE_PREFIX = 'vailo:pickVote:';

function safeDocId(key: string): string {
  // Firestore doc IDs cannot contain "/". Replace any with "_".
  return key.replace(/\//g, '_').slice(0, 256);
}

function localStorageKey(propertyId: string, docId: string): string {
  return `${LOCAL_VOTE_PREFIX}${propertyId}:${docId}`;
}

function readLocalVote(propertyId: string, docId: string): FeedbackVote {
  if (typeof window === 'undefined') return null;
  try {
    const raw = window.localStorage.getItem(localStorageKey(propertyId, docId));
    return raw === 'up' || raw === 'down' ? raw : null;
  } catch {
    return null;
  }
}

function writeLocalVote(propertyId: string, docId: string, vote: FeedbackVote): void {
  if (typeof window === 'undefined') return;
  try {
    if (vote === null) {
      window.localStorage.removeItem(localStorageKey(propertyId, docId));
    } else {
      window.localStorage.setItem(localStorageKey(propertyId, docId), vote);
    }
  } catch {
    // ignore
  }
}

export type PickFeedbackItem = {
  title: string;
  source?: string;
  googlePlaceId?: string;
  googleMapsUrl?: string;
  latitude?: number;
  longitude?: number;
  description?: string;
  category?: string;
};

export type PickFeedbackResult = {
  docId: string;
  previousVote: FeedbackVote;
  newVote: FeedbackVote;
};

/** Apply a thumbs-up / thumbs-down vote for a recommendation. */
export async function applyPickFeedback(
  propertyId: string,
  item: PickFeedbackItem,
  nextVote: FeedbackVote
): Promise<PickFeedbackResult> {
  const key = pickKeyForItem(item);
  if (!key) throw new Error('Cannot identify item for feedback.');
  const docId = safeDocId(key);

  const previousVote = readLocalVote(propertyId, docId);
  const ref = doc(db, 'properties', propertyId, 'picksFeedback', docId);

  // Delta on each counter (handles toggling between up/down/none).
  const deltaUp =
    (nextVote === 'up' ? 1 : 0) - (previousVote === 'up' ? 1 : 0);
  const deltaDown =
    (nextVote === 'down' ? 1 : 0) - (previousVote === 'down' ? 1 : 0);

  if (deltaUp === 0 && deltaDown === 0) {
    writeLocalVote(propertyId, docId, nextVote);
    return { docId, previousVote, newVote: nextVote };
  }

  const snap = await getDoc(ref);
  if (!snap.exists()) {
    await setDoc(ref, {
      key,
      title: item.title || '',
      source: item.source || 'ai',
      category: item.category || '',
      googlePlaceId: item.googlePlaceId || '',
      googleMapsUrl: item.googleMapsUrl || '',
      latitude: typeof item.latitude === 'number' ? item.latitude : null,
      longitude: typeof item.longitude === 'number' ? item.longitude : null,
      thumbsUp: Math.max(0, deltaUp),
      thumbsDown: Math.max(0, deltaDown),
      lastVoteAt: serverTimestamp(),
      createdAt: serverTimestamp(),
    });
  } else {
    await updateDoc(ref, {
      title: item.title || snap.data().title || '',
      source: item.source || snap.data().source || 'ai',
      category: item.category || snap.data().category || '',
      googlePlaceId: item.googlePlaceId || snap.data().googlePlaceId || '',
      googleMapsUrl: item.googleMapsUrl || snap.data().googleMapsUrl || '',
      latitude:
        typeof item.latitude === 'number' ? item.latitude : (snap.data().latitude ?? null),
      longitude:
        typeof item.longitude === 'number' ? item.longitude : (snap.data().longitude ?? null),
      thumbsUp: increment(deltaUp),
      thumbsDown: increment(deltaDown),
      lastVoteAt: serverTimestamp(),
    });
  }

  writeLocalVote(propertyId, docId, nextVote);
  return { docId, previousVote, newVote: nextVote };
}

/** Look up the local vote (cheap, no Firestore read). */
export function getLocalVote(propertyId: string, item: PickFeedbackItem): FeedbackVote {
  const key = pickKeyForItem(item);
  if (!key) return null;
  return readLocalVote(propertyId, safeDocId(key));
}

import {
  bareGooglePlaceId,
  extractPlaceIdFromMapsUrl,
  isBrokenPlaceMapsUrl,
  isDirectPlaceMapsUrl,
} from './geocoding';

/** Cretan / Greek spelling variants for Google Places search. */
const SEARCH_TITLE_ALIASES: Record<string, string[]> = {
  filaki: ['Phylaki', 'Filaki'],
  filakivillage: ['Phylaki', 'Filaki'],
  fres: ['Fres', 'Fres Village'],
  fresvillage: ['Fres', 'Fres Village'],
};

export function placeSearchTitleVariants(title: string): string[] {
  const clean = title.trim();
  if (!clean) return [];
  const norm = clean.toLowerCase().replace(/[^a-z0-9\u0370-\u03ff]/g, '');
  const aliases = SEARCH_TITLE_ALIASES[norm] || [];
  const out = new Set<string>([clean, ...aliases]);
  return [...out];
}

/** True when a pick is safe to show guests (DB-curated or resolvable on Google Maps). */
export function isPickVerified(item: Record<string, unknown>): boolean {
  if (item.source === 'database') return true;
  if (item.isProperty === true || item.source === 'property') return true;

  const placeId =
    bareGooglePlaceId(item.googlePlaceId as string | undefined) ||
    extractPlaceIdFromMapsUrl(item.googleMapsUrl as string | undefined);
  if (!placeId) return false;

  const mapsUrl = typeof item.googleMapsUrl === 'string' ? item.googleMapsUrl : '';
  if (mapsUrl && isBrokenPlaceMapsUrl(mapsUrl)) return false;

  const lat = item.latitude ?? item.lat;
  const lng = item.longitude ?? item.lng;
  const hasCoords =
    typeof lat === 'number' && typeof lng === 'number' && !isNaN(lat) && !isNaN(lng);

  const hasPhoto = typeof item.photoUrl === 'string' && item.photoUrl.trim().length > 0;
  const hasDirectMap = isDirectPlaceMapsUrl(mapsUrl);

  if (hasCoords && (hasPhoto || hasDirectMap || placeId)) return true;
  if (placeId && hasDirectMap) return true;

  return false;
}

export function filterUnverifiedFromPicksPlan(plan: Record<string, unknown> | null | undefined) {
  if (!plan || plan.type !== 'picks' || !Array.isArray(plan.categories)) return plan;

  const categories = (plan.categories as Array<Record<string, unknown>>).map((cat) => {
    const items = ((cat.items as Record<string, unknown>[]) || []).filter(
      (item) => isPickVerified(item)
    );
    return { ...cat, items };
  });

  return { ...plan, categories };
}

/** Shared place-name normalization for deduplicating AI / Google imports. */

const GENERIC_SUFFIXES = [
  'restaurant',
  'horseriding',
  'taverna',
  'cafeteria',
  'cafe',
  'coffee',
  'bar',
  'grill',
  'hotel',
  'resort',
  'beach',
  'agency',
  'shop',
  'studio',
  'studios',
];

const GEO_HINTS = [
  'beach',
  'village',
  'gorge',
  'cove',
  'bay',
  'monastery',
  'archaeological',
  'lake',
  'mountain',
  'park',
  'waterfall',
  'harbour',
  'port',
  'square',
  'cave',
  'ruins',
  'settlement',
  'hamlet',
];

const BUSINESS_HINTS = [
  'studio',
  'studios',
  'hotel',
  'resort',
  'restaurant',
  'taverna',
  'cafe',
  'bar',
  'grill',
  'shop',
  'agency',
  'apartments',
  'rooms',
  'villas',
  'suites',
  'lodge',
  'inn',
  'motel',
  // Activity / tour operators — frequently sit next to a beach and get returned
  // by Google for a beach search even though they are commercial venues.
  'safari',
  'jeep',
  'quad',
  'buggy',
  'kayak',
  'scuba',
  'snorkel',
  'cruise',
  'charter',
  'excursion',
  'watersports',
  'watersport',
  'rentals',
  'rental',
  'jetski',
];

export function normalizePlaceName(name: string): string {
  return String(name || '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\u0370-\u03ff]/g, '');
}

/** Strip parenthetical notes (e.g. Greek names) before Google search. */
export function sanitizePlaceSearchTitle(title: string): string {
  return String(title || '')
    .replace(/\([^)]*\)/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

export function nameCore(normalized: string): string {
  if (!normalized || normalized.length < 3) return normalized;
  let core = normalized;
  for (const suffix of GENERIC_SUFFIXES) {
    if (core.endsWith(suffix) && core.length > suffix.length + 2) {
      core = core.slice(0, -suffix.length);
    }
  }
  return core.length >= 3 ? core : normalized;
}

function includesHint(normalized: string, hints: string[]): boolean {
  return hints.some((h) => normalized.includes(h));
}

/** True when a beach/village pick would wrongly match a hotel/studio/etc. */
export function placeKindsConflict(requestedNorm: string, resolvedNorm: string): boolean {
  const geoReq = includesHint(requestedNorm, GEO_HINTS);
  const geoRes = includesHint(resolvedNorm, GEO_HINTS);
  const bizReq = includesHint(requestedNorm, BUSINESS_HINTS);
  const bizRes = includesHint(resolvedNorm, BUSINESS_HINTS);

  if (geoReq && bizRes && !geoRes) return true;
  if (bizReq && geoRes && !bizRes) return true;
  return false;
}

export function namesLikelySame(a: string, b: string): boolean {
  if (!a || !b) return false;
  if (a === b) return true;

  const ca = nameCore(a);
  const cb = nameCore(b);
  if (ca === cb && ca.length >= 4) {
    if (placeKindsConflict(a, b)) return false;
    return true;
  }

  const shorter = a.length <= b.length ? a : b;
  const longer = a.length <= b.length ? b : a;
  if (shorter.length >= 5 && longer.includes(shorter)) return true;

  if (ca.length >= 4 && cb.length >= 4 && (ca.includes(cb) || cb.includes(ca))) {
    if (placeKindsConflict(a, b)) return false;
    return true;
  }

  return false;
}

/** Check when accepting a Google Places result for a requested place name. */
export function placeNamesMatch(requested: string, resolved: string): boolean {
  const a = normalizePlaceName(requested);
  const b = normalizePlaceName(resolved);
  if (!a || !b) return false;
  if (a === b) return true;
  if (placeKindsConflict(a, b)) return false;

  const ca = nameCore(a);
  const cb = nameCore(b);
  if (ca === cb && ca.length >= 4) return true;

  // A distinctive core token (not a generic suffix) shared between the two names.
  if (ca.length >= 5 && b.includes(ca)) return true;
  if (cb.length >= 5 && a.includes(cb)) return true;

  const words = String(requested || '')
    .toLowerCase()
    .replace(/[^a-z0-9\u0370-\u03ff\s]/g, ' ')
    .split(/\s+/)
    .filter((w) => w.length >= 5 && !GENERIC_SUFFIXES.includes(w));
  return words.some((w) => b.includes(normalizePlaceName(w)));
}

/**
 * True when a resolved Google place is a fundamentally different *kind* than the
 * requested one (a geographic spot resolving to a business, or vice-versa). This
 * is the only signal we use to reject a Google resolution — it is location- and
 * language-agnostic, so it works for any region without hardcoded place lists.
 */
export function placeResolutionConflicts(requested: string, resolved: string): boolean {
  const a = normalizePlaceName(requested);
  const b = normalizePlaceName(resolved);
  if (!a || !b) return false;
  return placeKindsConflict(a, b);
}

/**
 * Remove a trailing ", <place>" qualifier the AI sometimes appends to a venue
 * name (e.g. "Taverna Glaros, Kalyves"). The map link and coordinates carry the
 * real location, and the AI's appended town is frequently wrong, so this is a
 * display-only cleanup applied to AI picks.
 */
export function stripTrailingLocality(title: string): string {
  const raw = String(title || '').trim();
  const commaIdx = raw.indexOf(',');
  if (commaIdx < 0) return raw;
  const head = raw.slice(0, commaIdx).trim();
  return head.length >= 3 ? head : raw;
}

import { getFunctions, httpsCallable } from 'firebase/functions';
import { normalizePlaceName } from './placeNameUtils';

export type ResolvedPlacePhoto = {
  photoUrl: string | null;
  googleMapsUrl?: string | null;
  googlePlaceId?: string | null;
  latitude?: number | null;
  longitude?: number | null;
  placeName?: string | null;
  discoveredPlaceId?: string | null;
  fromDiscoveredDb?: boolean;
  fromCache?: boolean;
  notFound?: boolean;
};

const sessionPhotoCache = new Map<string, ResolvedPlacePhoto>();

export async function resolvePlacePhoto(params: {
  title: string;
  area: string;
  country: string;
  areaId: string;
  latitude?: number;
  longitude?: number;
  anchorLat?: number;
  anchorLng?: number;
  maxKm?: number;
  knowledgeMode?: 'areas' | 'business' | 'any';
}): Promise<ResolvedPlacePhoto> {
  const normalized = normalizePlaceName(params.title);
  const coordSuffix =
    typeof params.latitude === 'number' && typeof params.longitude === 'number'
      ? `@${params.latitude.toFixed(4)},${params.longitude.toFixed(4)}`
      : '';
  const key = `${normalized}::${params.country}::${params.areaId}${coordSuffix}`;
  const exactHit = sessionPhotoCache.get(key);
  if (exactHit) return exactHit;

  const functions = getFunctions();
  const callable = httpsCallable(functions, 'resolvePlacePhoto');
  const result = await callable({
    title: params.title,
    area: params.area,
    country: params.country,
    areaId: params.areaId,
    latitude: params.latitude,
    longitude: params.longitude,
    anchorLat: params.anchorLat,
    anchorLng: params.anchorLng,
    maxKm: params.maxKm,
    knowledgeMode: params.knowledgeMode || 'any',
  });

  const data = result.data as ResolvedPlacePhoto;
  sessionPhotoCache.set(key, data);
  return data;
}

