import { placeNamesMatch } from './placeNameUtils';

export type PropertyBookendContext = {
  propertyTitle: string;
  propertyPhotoUrl?: string;
  propertyCoords: { lat: number; lng: number } | null;
  locationLabel?: string;
  defaultStartTime?: string;
  defaultEndTime?: string;
};

function isPropertyTimelineStop(
  item: Record<string, unknown> | null | undefined,
  ctx: PropertyBookendContext
): boolean {
  if (!item) return false;
  if (item.isProperty === true || item.source === 'property') return true;

  const title = String(item.title || '').trim();
  if (!title) return false;
  if (placeNamesMatch(title, ctx.propertyTitle)) return true;

  const label = (ctx.locationLabel || '').trim();
  if (label && (title === label || title.includes(label))) return true;

  const nearStripped = label.replace(/^near\s+/i, '').trim();
  if (nearStripped && placeNamesMatch(title, nearStripped)) return true;

  return false;
}

function buildPropertyStop(
  time: string,
  description: string,
  transportToNext: string,
  ctx: PropertyBookendContext
): Record<string, unknown> {
  const stop: Record<string, unknown> = {
    time,
    title: ctx.propertyTitle,
    description,
    transportToNext,
    source: 'property',
    isProperty: true,
    photoUrl: ctx.propertyPhotoUrl || '',
    googleMapsUrl: '',
    googlePlaceId: '',
  };
  if (ctx.propertyCoords) {
    stop.latitude = ctx.propertyCoords.lat;
    stop.longitude = ctx.propertyCoords.lng;
  }
  return stop;
}

/**
 * When the guest plans from their accommodation, the timeline must start and
 * end at the property — not at random stops that only inherited the property photo.
 */
export function ensureTimelinePropertyBookends(
  plan: unknown,
  ctx: PropertyBookendContext
): unknown {
  if (!plan || typeof plan !== 'object') return plan;
  const data = plan as Record<string, unknown>;
  if (data.type !== 'timeline' || !Array.isArray(data.plan) || data.plan.length === 0) {
    return plan;
  }

  const original = data.plan as Record<string, unknown>[];
  const core = original.filter((item) => !isPropertyTimelineStop(item, ctx));

  if (core.length === 0) {
    const departureOnly = buildPropertyStop(
      ctx.defaultStartTime || '09:00 AM',
      `Your day begins at ${ctx.propertyTitle}.`,
      '',
      ctx
    );
    const returnOnly = buildPropertyStop(
      ctx.defaultEndTime || departureOnly.time as string,
      `Return to ${ctx.propertyTitle} to finish your day.`,
      '',
      ctx
    );
    return { ...data, plan: [departureOnly, returnOnly] };
  }

  const peeledFirst = original.find((item) => isPropertyTimelineStop(item, ctx));
  const peeledLast = [...original].reverse().find((item) => isPropertyTimelineStop(item, ctx));

  const departureTime =
    (peeledFirst?.time as string) ||
    ctx.defaultStartTime ||
    (core[0]?.time as string) ||
    '09:00 AM';

  const returnTime =
    (peeledLast?.time as string) ||
    ctx.defaultEndTime ||
    (core[core.length - 1]?.time as string) ||
    departureTime;

  const transportToFirst =
    (typeof peeledFirst?.transportToNext === 'string' && peeledFirst.transportToNext.trim()) ||
    (typeof core[0]?.transportToNext === 'string' && core[0].transportToNext.trim()) ||
    '';

  const departure = buildPropertyStop(
    departureTime,
    `Your day begins at ${ctx.propertyTitle}.`,
    transportToFirst,
    ctx
  );

  const returnStop = buildPropertyStop(
    returnTime,
    `Return to ${ctx.propertyTitle} to finish your day.`,
    '',
    ctx
  );

  return { ...data, plan: [departure, ...core, returnStop] };
}

/** Recompute timeline stop times and travel hints from coordinates (no paid routing APIs). */

export type TimelineScheduleOptions = {
  /** 24h start e.g. "09:00" */
  startTime24: string;
  /** Absolute end minute (may exceed 24h for next-day returns). */
  endMin: number;
  /** Minutes to spend at each activity stop (auto-sized if omitted). */
  minDwellMinutes?: number;
  maxDwellMinutes?: number;
};

function parseTime24ToMinutes(time: string): number {
  const [h, m] = time.split(':').map(Number);
  if (isNaN(h) || isNaN(m)) return 9 * 60;
  return h * 60 + m;
}

function formatTime12(minutes: number, nextDay = false): string {
  const normalized = ((minutes % (24 * 60)) + 24 * 60) % (24 * 60);
  const h = Math.floor(normalized / 60);
  const m = normalized % 60;
  const period = h >= 12 ? 'PM' : 'AM';
  const h12 = h % 12 || 12;
  const base = `${h12}:${m.toString().padStart(2, '0')} ${period}`;
  return nextDay ? `${base} (next day)` : base;
}

function extractItemCoords(item: Record<string, unknown>): { lat: number; lng: number } | null {
  const lat = item.latitude ?? item.lat;
  const lng = item.longitude ?? item.lng;
  const parsedLat = typeof lat === 'number' ? lat : parseFloat(String(lat ?? ''));
  const parsedLng = typeof lng === 'number' ? lng : parseFloat(String(lng ?? ''));
  if (!isNaN(parsedLat) && !isNaN(parsedLng)) return { lat: parsedLat, lng: parsedLng };
  return null;
}

/** Road-ish distance in km (Haversine × winding factor). */
function drivingKm(
  a: { lat: number; lng: number },
  b: { lat: number; lng: number }
): number {
  const R = 6371;
  const dLat = (b.lat - a.lat) * (Math.PI / 180);
  const dLng = (b.lng - a.lng) * (Math.PI / 180);
  const s =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(a.lat * (Math.PI / 180)) *
      Math.cos(b.lat * (Math.PI / 180)) *
      Math.sin(dLng / 2) ** 2;
  const straight = R * 2 * Math.atan2(Math.sqrt(s), Math.sqrt(1 - s));
  return straight * 1.35;
}

function estimateDriveMinutes(km: number): number {
  if (km < 0.15) return 5;
  if (km < 1) return Math.max(5, Math.round(km * 12 + 4)); // walk / very short
  const speedKmh = km < 8 ? 40 : 55;
  return Math.max(5, Math.round((km / speedKmh) * 60));
}

function isPropertyStop(item: Record<string, unknown>): boolean {
  return item.isProperty === true || item.source === 'property';
}

function formatLegTransport(toTitle: string, driveMin: number, km: number): string {
  const dest = String(toTitle || 'next stop').trim();
  if (km < 0.8) {
    return `${driveMin} min walk · ${km.toFixed(1)} km to ${dest}`;
  }
  return `${driveMin} min drive · ${km.toFixed(1)} km to ${dest}`;
}

type LegInfo = { minutes: number; km: number };

function computeLegs(items: Record<string, unknown>[]): LegInfo[] {
  const legs: LegInfo[] = [];
  for (let i = 0; i < items.length - 1; i++) {
    const from = extractItemCoords(items[i]);
    const to = extractItemCoords(items[i + 1]);
    if (from && to) {
      const km = drivingKm(from, to);
      legs.push({ km, minutes: estimateDriveMinutes(km) });
    } else {
      legs.push({ km: 0, minutes: 12 });
    }
  }
  return legs;
}

