import { useEffect, useLayoutEffect, useMemo, useRef, useState } from 'react';
import { useGuestLocale } from '../../context/GuestLocaleContext';
import { resolveLocalizedString } from '../../lib/propertyContentLocales';

type Props = {
  text?: string;
  doc?: Record<string, unknown> | null;
  field?: string;
  /** Number of lines to show when collapsed. */
  lines?: number;
  className?: string;
  bodyClassName?: string;
  toggleClassName?: string;
  onExpand?: () => void;
};

const useIsomorphicLayoutEffect = typeof window !== 'undefined' ? useLayoutEffect : useEffect;

/**
 * Clamps `text` to `lines` lines and shows a "more" / "less" toggle when truncated.
 * Host content is read from stored per-locale fields (see propertyContentLocales).
 */
export default function ExpandableDescription({
  text,
  doc,
  field = 'description',
  lines = 3,
  className = '',
  bodyClassName = 'text-base text-gray-600 leading-relaxed',
  toggleClassName = 'mt-1.5 text-sm font-semibold normal-case tracking-wide text-[#0B4F5C] hover:text-[#C5A059] transition-colors min-h-[44px]',
  onExpand,
}: Props) {
  const { t, locale, contentPrimaryLocale, contentReviewedLocales } = useGuestLocale();
  const ref = useRef<HTMLParagraphElement>(null);
  const [isClamped, setIsClamped] = useState(false);
  const [expanded, setExpanded] = useState(false);

  const displayText = useMemo(() => {
    if (doc) {
      return resolveLocalizedString(doc, field, locale, contentPrimaryLocale, contentReviewedLocales);
    }
    return String(text || '').trim();
  }, [doc, field, locale, contentPrimaryLocale, contentReviewedLocales, text]);

  useIsomorphicLayoutEffect(() => {
    const el = ref.current;
    if (!el || !displayText) {
      setIsClamped(false);
      return;
    }
    setIsClamped(el.scrollHeight - el.clientHeight > 1);
  }, [displayText, lines]);

  if (!displayText) return null;

  return (
    <div className={className}>
      <p
        ref={ref}
        className={`${bodyClassName} whitespace-pre-wrap`}
        style={
          expanded
            ? undefined
            : {
                display: '-webkit-box',
                WebkitLineClamp: lines,
                WebkitBoxOrient: 'vertical',
                overflow: 'hidden',
              }
        }
      >
        {displayText}
      </p>
      {(isClamped || expanded) && (
        <button
          type="button"
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
            setExpanded((v) => {
              if (!v) onExpand?.();
              return !v;
            });
          }}
          className={toggleClassName}
        >
          {expanded ? t('less') : t('more')}
        </button>
      )}
    </div>
  );
}

import { useEffect, useMemo, useRef } from 'react';
import { useGuestAnalytics } from '../../context/GuestAnalyticsContext';

type GemLike = { id: string; name?: string };

/**
 * Logs gem_impression once per gem id when the card is ≥50% visible for ~1s.
 */
export default function GemImpressionTracker({
  gems,
  children,
}: {
  gems: GemLike[];
  children: React.ReactNode;
}) {
  const { enabled, track } = useGuestAnalytics();
  const seenRef = useRef<Set<string>>(new Set());
  const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());
  const gemIdsKey = useMemo(
    () => gems.map((g) => g.id).sort().join(','),
    [gems]
  );

  useEffect(() => {
    if (!enabled || gems.length === 0) return;

    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          const gemId = entry.target.getAttribute('data-gem-id');
          if (!gemId || seenRef.current.has(gemId)) continue;

          if (entry.isIntersecting && entry.intersectionRatio >= 0.5) {
            if (timersRef.current.has(gemId)) continue;
            const name = entry.target.getAttribute('data-gem-name') || undefined;
            const timer = setTimeout(() => {
              timersRef.current.delete(gemId);
              if (seenRef.current.has(gemId)) return;
              seenRef.current.add(gemId);
              track('gem_impression', { gemId, gemName: name });
            }, 1000);
            timersRef.current.set(gemId, timer);
          } else {
            const t = timersRef.current.get(gemId);
            if (t) {
              clearTimeout(t);
              timersRef.current.delete(gemId);
            }
          }
        }
      },
      { threshold: [0.5] }
    );

    const nodes = document.querySelectorAll('[data-gem-id]');
    nodes.forEach((node) => observer.observe(node));

    return () => {
      observer.disconnect();
      timersRef.current.forEach((t) => clearTimeout(t));
      timersRef.current.clear();
    };
  }, [enabled, gemIdsKey, gems.length, track]);

  return <>{children}</>;
}

