export function useAreaContentLocaleSettings(country: string, areaId: string) {
  const { languages } = usePlatformLanguages();
  const platformCodes = useMemo(
    () => languages.map((l) => l.shortName),
    [languages]
  );

  const [rawSettings, setRawSettings] = useState<PropertyContentLocaleSettings>(() =>
    parseAreaContentLocaleSettings(undefined)
  );

  useEffect(() => {
    if (!country || !areaId) return;
    return onSnapshot(doc(db, 'countries', country, 'areas', areaId), (snap) => {
      setRawSettings(
        parseAreaContentLocaleSettings(
          snap.exists() ? (snap.data() as Record<string, unknown>) : undefined
        )
      );
    });
  }, [country, areaId]);

  return useMemo(
    () => resolveAreaContentLocaleSettings(rawSettings, platformCodes),
    [rawSettings, platformCodes]
  );
}

import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { doc, onSnapshot } from 'firebase/firestore';
import { db } from '../lib/firebase';

/** Area admin routes use the Firestore area document id in the URL (not the display name). */
export function useAreaRouteParams() {
  const { country, area } = useParams<{ country: string; area: string }>();
  const decodedCountry = decodeURIComponent(country || '').trim();
  const areaId = decodeURIComponent(area || '').trim();
  const [areaName, setAreaName] = useState(areaId);

  useEffect(() => {
    if (!decodedCountry || !areaId) return;
    return onSnapshot(doc(db, 'countries', decodedCountry, 'areas', areaId), (snap) => {
      const name = snap.exists() ? String(snap.data()?.name || '').trim() : '';
      setAreaName(name || areaId);
    });
  }, [decodedCountry, areaId]);

  return { country: decodedCountry, areaId, areaName };
}

import { useCallback, useEffect, useState } from 'react';
import { getFunctions, httpsCallable } from 'firebase/functions';

export type BillingLineItem = {
  label: string;
  cost: number;
  count?: number;
};

export type BillingInvoice = {
  source: 'bigquery' | 'ledger';
  configured: boolean;
  monthKey: string;
  totalCost: number;
  lineItems: BillingLineItem[];
  currency: string;
  magicFill?: number;
  note?: string;
  bigQueryError?: string;
};

export function useBillingInvoice(monthKey?: string) {
  const [invoice, setInvoice] = useState<BillingInvoice | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchInvoice = useCallback(async (key?: string) => {
    setLoading(true);
    setError(null);
    try {
      const functions = getFunctions();
      const getBillingInvoice = httpsCallable<{ monthKey?: string }, BillingInvoice>(
        functions,
        'getBillingInvoice'
      );
      const result = await getBillingInvoice(key ? { monthKey: key } : {});
      setInvoice(result.data);
    } catch (err) {
      console.error('getBillingInvoice:', err);
      setError('Could not load invoice data. Deploy getBillingInvoice if you have not yet.');
      setInvoice(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchInvoice(monthKey);
  }, [monthKey, fetchInvoice]);

  return { invoice, loading, error, refresh: () => fetchInvoice(monthKey) };
}

import { useCallback, useEffect, useRef, useState } from 'react';
import {
  buildLocalizedFirestorePayload,
  mergeLegacyIntoLocaleMap,
  normalizeLocaleCode,
  readLocaleMap,
  setLocaleFieldValue,
  type LocaleStringMap,
} from '../lib/propertyContentLocales';

export function useContentLocaleEditor(
  primaryLocale: string,
  fields: string[],
  sourceDoc?: Record<string, unknown> | null
) {
  const primary = normalizeLocaleCode(primaryLocale) || 'en';
  const [contentLocale, setContentLocale] = useState(primary);

  const buildMapsFromDoc = useCallback(
    (doc?: Record<string, unknown> | null) => {
      const initial: Record<string, LocaleStringMap> = {};
      for (const field of fields) {
        initial[field] = mergeLegacyIntoLocaleMap(
          readLocaleMap(doc, field),
          typeof doc?.[field] === 'string' ? (doc[field] as string) : undefined,
          primary
        );
      }
      return initial;
    },
    [fields, primary]
  );

  const [maps, setMaps] = useState<Record<string, LocaleStringMap>>(() => buildMapsFromDoc(sourceDoc));
  const lastSyncedSourceRef = useRef<Record<string, unknown> | null | undefined>(undefined);

  useEffect(() => {
    if (lastSyncedSourceRef.current === sourceDoc) return;
    lastSyncedSourceRef.current = sourceDoc;
    setMaps(buildMapsFromDoc(sourceDoc));
  }, [sourceDoc, buildMapsFromDoc, primary]);

  const getValue = useCallback(
    (field: string) => {
      const map = maps[field] || {};
      const code = normalizeLocaleCode(contentLocale) || primary;
      return (map[code] ?? '').toString();
    },
    [maps, contentLocale, primary]
  );

  const getValueForLocale = useCallback(
    (field: string, locale: string) => {
      const map = maps[field] || {};
      const code = normalizeLocaleCode(locale) || primary;
      return (map[code] ?? '').toString();
    },
    [maps, primary]
  );

  const setValue = useCallback(
    (field: string, value: string) => {
      const code = normalizeLocaleCode(contentLocale) || primary;
      setMaps((prev) => ({
        ...prev,
        [field]: setLocaleFieldValue(prev[field] || {}, code, value, { trim: false }),
      }));
    },
    [contentLocale, primary]
  );

  const applyPrimaryFields = useCallback(
    (values: Record<string, string>) => {
      setMaps((prev) => {
        const next = { ...prev };
        for (const [field, value] of Object.entries(values)) {
          if (!fields.includes(field)) continue;
          next[field] = setLocaleFieldValue(next[field] || {}, primary, value);
        }
        return next;
      });
    },
    [primary, fields]
  );

  const applyTranslatedFields = useCallback(
    (targetLocale: string,
    values: Record<string, string>) => {
      const code = normalizeLocaleCode(targetLocale);
      if (!code) return;
      setMaps((prev) => {
        const next = { ...prev };
        for (const [field, value] of Object.entries(values)) {
          if (!fields.includes(field)) continue;
          next[field] = setLocaleFieldValue(next[field] || {}, code, value);
        }
        return next;
      });
    },
    [fields]
  );

  const getPrimaryValue = useCallback(
    (field: string) => (maps[field]?.[primary] ?? '').toString(),
    [maps, primary]
  );

  const buildPayload = useCallback(
    () => buildLocalizedFirestorePayload(fields, maps, primary, {}),
    [fields, maps, primary]
  );

  const resetMaps = useCallback(() => {
    lastSyncedSourceRef.current = null;
    setMaps(buildMapsFromDoc(null));
    setContentLocale(primary);
  }, [buildMapsFromDoc, primary]);

  const loadFromDoc = useCallback(
    (doc: Record<string, unknown> | null | undefined, options?: { preserveLocale?: boolean }) => {
      lastSyncedSourceRef.current = doc;
      setMaps(buildMapsFromDoc(doc));
      if (!options?.preserveLocale) {
        setContentLocale(primary);
      }
    },
    [buildMapsFromDoc, primary]
  );

  return {
    contentLocale,
    setContentLocale,
    primaryLocale: primary,
    getValue,
    getValueForLocale,
    setValue,
    getPrimaryValue,
    applyPrimaryFields,
    applyTranslatedFields,
    buildPayload,
    resetMaps,
    loadFromDoc,
  };
}

